What does this program print?

```cpp
#include <iostream>

void show(int& x)  { std::cout << "L\n"; }
void show(int&& x) { std::cout << "R\n"; }

int main() {
    int a = 1;
    int&& r = 2;
    show(a);
    show(r);
    show(3);
    return 0;
}
```

